(1697, 19331, 7, 1344, 'Legal Auditor', 'سند القسمة الرضائية المرفق قديم.. ع أرض الواقع مغاير', '2026-04-04 13:44:05', '2026-04-05 14:17:37'),
(1698, 19332, 7, 1344, 'Legal Auditor', 'سند الملكية غير مرفق.. سند القسمة الرضائية المرفق قسم البناية لنصفين ع فريقين بالتساوي ملكية مشتركة ع الشيوع', '2026-04-04 13:44:05', '2026-04-05 13:56:27'),
(1699, 19333, 7, 1344, 'Legal Auditor', 'سند الملكية غير مرفق', '2026-04-04 13:44:05', '2026-04-05 13:40:36'),
(1700, 19334, 7, 1344, 'Legal Auditor', 'وفقًا للما ذكر في سند القسمة الرضائية المرفق للأرض والمبنى، بأن الطرف الأول يمتلك المحلات الشمالية بالتساوي فالملكية مشتركة، كما أن أجمد أبو هلال ليس من ضمن الطرف الأول، يرجى ارفاق ما يثبت ملكيته للحاصل الشمالي وفق ما هو مدعي بملكيته هنا.', '2026-04-04 13:44:05', '2026-04-05 14:07:38'),
(1701, 19335, 7, 1344, 'Legal Auditor', 'يرجى اثبات سند الملكية فسند القسمة غير واضح والملكية وفقًا له بقيت مشتركة قسمت البناية بين طرفين دون تخصيص كل طابق ووحدة لكل شخص', '2026-04-04 13:44:05', '2026-04-05 14:10:48'),
(1702, 19336, 7, 1344, 'Legal Auditor', 'يرجى ارفاق سند الملكية بأن تلك الوحدة مخصصة له', '2026-04-04 13:44:05', '2026-04-05 14:12:50'),
(1703, 19337, 7, 1344, 'Legal Auditor', 'سند الملكية غير مرفق لإثبات ملكيته للوحدة المذكورة', '2026-04-04 13:44:05', '2026-04-05 13:48:27'),
(1704, 19338, 8, 1344, 'Legal Auditor', 'تم', '2026-04-04 13:44:05', '2026-04-05 13:38:40'),
(1705, 19339, 7, 1344, 'Legal Auditor', 'وحدة خدمات المبنى ملك مشترك لجميع الملاك، وإن وجدت سندات تعكس ذلك فيستوجب ارفاقها.', '2026-04-04 13:44:05', '2026-04-05 13:47:20'),
(1706, 17423, 7, 1344, 'Legal Auditor', 'سند الملكية غير مرفق', '2026-04-04 13:44:05', '2026-04-05 14:33:45'),
(1707, 17424, 7, 1344, 'Legal Auditor', 'سند الملكية غير مرفق', '2026-04-04 13:44:05', '2026-04-05 14:35:38'),
